import { auth } from './authApi';

const BASE_URL = 'https://taynguyen1.weathervietnam.vn/api';
const TOKEN_KEY = 'aiJwt'; // ✅ same key với authApi.js

const request = async (path, options = {}) => {
  const token = localStorage.getItem(TOKEN_KEY); // ✅ lấy trực tiếp thay vì auth.getToken()
  const headers = {
    'Content-Type': 'application/json',
    accept: 'application/json',
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
    ...(options.headers || {}),
  };

  const res = await fetch(`${BASE_URL}${path}`, { ...options, headers });

  if (res.status === 401) {
    auth.removeToken();
    window.location.reload(); // ✅ đồng bộ với callApi trong authApi.js
    return;
  }

  if (!res.ok) {
    let errMsg = `${res.status} ${res.statusText}`;
    try {
      const errData = await res.json();
      const rawMsg = errData?.message || errData?.detail || errMsg;
      // ✅ cắt Flask 404 message thừa
      errMsg = typeof rawMsg === 'string'
        ? rawMsg.split('You have requested')[0].trim()
        : JSON.stringify(rawMsg);
    } catch { /* ignore */ }
    throw new Error(errMsg);
  }

  if (res.status === 204) return null;

  const ct = res.headers.get('content-type') || '';
  return ct.includes('application/json') ? res.json() : res.text();
};

export const stationGroupApi = {
  getAll: (params = {}) => {
    const query = new URLSearchParams();
    if (params.page_size !== undefined) query.append('page_size', params.page_size);
    if (params.search) query.append('search', params.search);
    const qs = query.toString();
    return request(`/stationgroups/${qs ? '?' + qs : ''}`);
  },
  getByCode: (code) => request(`/stationgroups/${encodeURIComponent(code)}`),
  create: (payload) => request('/stationgroups/', {
    method: 'POST',
    body: JSON.stringify(payload),
  }),
  update: (code, payload) => request(`/stationgroups/${encodeURIComponent(code)}`, {
    method: 'PUT',
    body: JSON.stringify(payload),
  }),
  delete: (code) => request(`/stationgroups/${encodeURIComponent(code)}`, {
    method: 'DELETE',
  }),
};
